import torch
import requests
from torch import hub
from torchaio import Dataset
from tqdm import trange, tqdm

def download_model(url):
    response = requests.get(url)
    if response.status_code == 200:
        state_dict = torch.load(response.content, map_location='cpu')
        return state_dict
    else:
        raise Exception(f"Failed to download model from {url}")

def fine_tune(model, dataset_train, dataset_val=None):
    criterion = torch.nn.CrossEntropyLoss()
    optimizer = torch.optim.SGD(model.parameters(), lr=0.01)

    epochs = 10

    for epoch in range(epochs):
        model.train()
        running_loss = 0.0
        for i, (inputs, labels) in enumerate(dataset_train):
            optimizer.zero_grad()

            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()

            running_loss += loss.item()
            if i % 100 == 99:
                print(f"Epoch [{epoch+1}/{epochs}], Step [{i+1}/{len(dataset_train)}], Loss: {running_loss/100}")
                running_loss = 0.0

        if dataset_val is not None:
            model.eval()
            val_loss = 0.0
            with torch.no_grad():
                for inputs, labels in tqdm(dataset_val):
                    outputs = model(inputs)
                    loss = criterion(outputs, labels)
                    val_loss += loss.item()
            print(f"Validation Loss: {val_loss / len(dataset_val)}")

